/**
 * Stencil custom output target — auto-generates Storybook stories from component metadata.
 *
 * Runs on every build (including watch mode). Only generates a story file when:
 *   1. The component has no existing .stories.ts file, OR
 *   2. The existing file contains the @auto-generated marker comment.
 *
 * Manually authored stories (without the marker) are never overwritten.
 */

const { existsSync, writeFileSync, readFileSync, mkdirSync } = require('fs');
const { join, dirname } = require('path');

const AUTO_GEN_MARKER = '// @auto-generated by storybook-output-target — edits will be overwritten on next build';

function storybookOutputTarget(opts = {}) {
  return {
    type: 'custom',
    name: 'storybook-stories',
    generator: async (config, _compilerCtx, _buildCtx, docs) => {
      const rootDir = config.rootDir || process.cwd();
      let generated = 0;
      let skipped = 0;

      for (const component of docs.components) {
        if (!component.filePath) continue;

        const tag = component.tag;
        const name = tag.replace('ts-', '');
        const compDir = component.dirPath || join(rootDir, dirname(component.filePath));
        const storiesPath = join(compDir, `${name}.stories.ts`);

        if (existsSync(storiesPath)) {
          const existing = readFileSync(storiesPath, 'utf-8');
          if (!existing.includes('@auto-generated')) {
            skipped++;
            continue;
          }
        }

        const content = generateStory(component);
        mkdirSync(dirname(storiesPath), { recursive: true });
        writeFileSync(storiesPath, content, 'utf-8');
        generated++;
      }

      if (config.logger) {
        config.logger.info(`storybook-stories: generated ${generated}, skipped ${skipped} manual`);
      }
    },
  };
}

function generateStory(component) {
  const tag = component.tag;
  const name = tag.replace('ts-', '');
  const title = `Components/${pascalCase(name)}`;
  const props = component.props || [];
  const slots = component.slots || [];

  const lines = [];

  lines.push(AUTO_GEN_MARKER);
  lines.push('');
  lines.push(`export default {`);
  lines.push(`  title: '${title}',`);
  lines.push(`  tags: ['autodocs'],`);

  // --- argTypes ---
  if (props.length > 0 || hasDefaultSlot(slots)) {
    lines.push(`  argTypes: {`);

    for (const prop of props) {
      lines.push(...argTypeLines(prop));
    }

    if (hasDefaultSlot(slots)) {
      lines.push(`    slotContent: { control: 'text', description: 'Default slot content' },`);
    }

    lines.push(`  },`);
  }

  lines.push(`};`);
  lines.push('');

  // --- Template ---
  lines.push(`const Template = (args: Record<string, unknown>) => {`);
  lines.push(`  const attrs: string[] = [];`);

  for (const prop of props) {
    if (prop.type === 'boolean') {
      lines.push(`  if (args.${prop.name}) attrs.push('${prop.attr || prop.name}');`);
    } else {
      lines.push(`  if (args.${prop.name} != null) attrs.push(\`${prop.attr || prop.name}="\${args.${prop.name}}"\`);`);
    }
  }

  const slotContent = hasDefaultSlot(slots)
    ? '${args.slotContent || \'\'}'
    : '';
  const namedSlots = slots.filter(s => s.name !== '');

  lines.push(`  return \`<${tag} \${attrs.join(' ')}>${slotContent}`);

  for (const slot of namedSlots) {
    lines.push(`    <span slot="${slot.name}">\${args['slot_${slot.name}'] || ''}</span>`);
  }

  lines.push(`  </${tag}>\`;`);
  lines.push(`};`);
  lines.push('');

  // --- Default story ---
  const defaultArgs = buildDefaultArgs(props, slots);
  lines.push(`export const Default = Object.assign(Template.bind({}) as typeof Template & { args: Record<string, unknown> }, {`);
  lines.push(`  args: ${JSON.stringify(defaultArgs, null, 4).replace(/\n/g, '\n  ')},`);
  lines.push(`});`);
  lines.push('');

  // --- Variant stories for union-type props ---
  const variantProp = props.find(p => p.name === 'variant' && p.values.length > 1);
  if (variantProp) {
    lines.push(...variantStory(tag, variantProp, slots));
  }

  const sizeProp = props.find(p => p.name === 'size' && p.values.length > 1);
  if (sizeProp) {
    lines.push(...sizeStory(tag, sizeProp, slots));
  }

  const appearanceProp = props.find(p => p.name === 'appearance' && p.values.length > 1);
  if (appearanceProp) {
    lines.push(...unionPropStory(tag, appearanceProp, 'Appearances', slots));
  }

  // --- States story (disabled, loading, etc.) ---
  const booleanStateProps = props.filter(
    p => p.type === 'boolean' && ['disabled', 'loading', 'readonly', 'checked'].includes(p.name)
  );
  if (booleanStateProps.length > 0) {
    lines.push(...statesStory(tag, booleanStateProps, slots));
  }

  return lines.join('\n') + '\n';
}

// --- Helpers ---

function argTypeLines(prop) {
  const lines = [];
  const controlInfo = getControlType(prop);
  const desc = prop.docs ? `, description: '${escapeSingleQuote(prop.docs)}'` : '';

  if (controlInfo.type === 'select') {
    lines.push(`    ${prop.name}: {`);
    lines.push(`      control: 'select',`);
    lines.push(`      options: [${controlInfo.options.map(v => `'${v}'`).join(', ')}]${desc ? `,` : ''}`);
    if (desc) lines.push(`      description: '${escapeSingleQuote(prop.docs)}'`);
    lines.push(`    },`);
  } else {
    lines.push(`    ${prop.name}: { control: '${controlInfo.type}'${desc} },`);
  }

  return lines;
}

function getControlType(prop) {
  if (prop.type === 'boolean') return { type: 'boolean' };
  if (prop.type === 'number') return { type: 'number' };

  const unionValues = (prop.values || [])
    .filter(v => v.type === 'string' && v.value)
    .map(v => v.value);

  if (unionValues.length > 1) {
    return { type: 'select', options: unionValues };
  }

  return { type: 'text' };
}

function buildDefaultArgs(props, slots) {
  const args = {};

  for (const prop of props) {
    if (prop.default != null && prop.default !== 'undefined') {
      const cleaned = prop.default.replace(/^'|'$/g, '');
      if (prop.type === 'boolean') {
        args[prop.name] = cleaned === 'true';
      } else if (prop.type === 'number') {
        args[prop.name] = Number(cleaned);
      } else {
        args[prop.name] = cleaned;
      }
    }
  }

  if (hasDefaultSlot(slots)) {
    args['slotContent'] = 'Content';
  }

  return args;
}

function variantStory(tag, prop, slots) {
  const content = hasDefaultSlot(slots) ? (s) => s : () => '';
  const values = prop.values.filter(v => v.value).map(v => v.value);
  const lines = [];

  lines.push(`export const Variants = () => \``);
  lines.push(`  <div style="display: flex; gap: 8px; flex-wrap: wrap; align-items: center;">`);
  for (const value of values) {
    lines.push(`    <${tag} variant="${value}">${content(pascalCase(value))}</${tag}>`);
  }
  lines.push(`  </div>`);
  lines.push(`\`;`);
  lines.push('');

  return lines;
}

function sizeStory(tag, prop, slots) {
  const content = hasDefaultSlot(slots) ? (s) => s : () => '';
  const values = prop.values.filter(v => v.value).map(v => v.value);
  const lines = [];

  lines.push(`export const Sizes = () => \``);
  lines.push(`  <div style="display: flex; gap: 8px; flex-wrap: wrap; align-items: center;">`);
  for (const value of values) {
    lines.push(`    <${tag} size="${value}">${content(value.toUpperCase())}</${tag}>`);
  }
  lines.push(`  </div>`);
  lines.push(`\`;`);
  lines.push('');

  return lines;
}

function unionPropStory(tag, prop, storyName, slots) {
  const content = hasDefaultSlot(slots) ? (s) => s : () => '';
  const values = prop.values.filter(v => v.value).map(v => v.value);
  const lines = [];

  lines.push(`export const ${storyName} = () => \``);
  lines.push(`  <div style="display: flex; gap: 8px; flex-wrap: wrap; align-items: center;">`);
  for (const value of values) {
    lines.push(`    <${tag} ${prop.attr || prop.name}="${value}">${content(pascalCase(value))}</${tag}>`);
  }
  lines.push(`  </div>`);
  lines.push(`\`;`);
  lines.push('');

  return lines;
}

function statesStory(tag, boolProps, slots) {
  const content = hasDefaultSlot(slots) ? (s) => s : () => '';
  const lines = [];

  lines.push(`export const States = () => \``);
  lines.push(`  <div style="display: flex; gap: 8px; flex-wrap: wrap; align-items: center;">`);
  lines.push(`    <${tag}>${content('Default')}</${tag}>`);
  for (const prop of boolProps) {
    lines.push(`    <${tag} ${prop.attr || prop.name}>${content(pascalCase(prop.name))}</${tag}>`);
  }
  lines.push(`  </div>`);
  lines.push(`\`;`);
  lines.push('');

  return lines;
}

function hasDefaultSlot(slots) {
  return slots.some(s => s.name === '');
}

function pascalCase(str) {
  return str
    .split(/[-_\s]+/)
    .map(s => s.charAt(0).toUpperCase() + s.slice(1))
    .join('');
}

function escapeSingleQuote(str) {
  return str.replace(/'/g, "\\'");
}

module.exports = { storybookOutputTarget };
